import{_ as e,o as i,c as n,ag as a}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Integrations","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/100_integrations/external_integrations.md","filePath":"10_core/40_service_apps/100_integrations/external_integrations.md"}'),r={name:"10_core/40_service_apps/100_integrations/external_integrations.md"};function o(s,t,l,d,c,g){return i(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to &quot;Integrations&quot;">​</a></h1><p>Integrations are connections to external systems. They are not canonical data sources — they are inputs that feed into the Spine.</p><h2 id="integration-rule" tabindex="-1">Integration Rule <a class="header-anchor" href="#integration-rule" aria-label="Permalink to &quot;Integration Rule&quot;">​</a></h2><blockquote><p>All external data entering QiOS must pass through the registration pipeline. No integration may write directly to canonical tables.</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>External System → Integration API → Pipeline → QiArchive → Canonical Record</span></span></code></pre></div><h2 id="planned-integrations" tabindex="-1">Planned Integrations <a class="header-anchor" href="#planned-integrations" aria-label="Permalink to &quot;Planned Integrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Integration</th><th>Status</th><th>Entry point</th></tr></thead><tbody><tr><td>Assigned watch folders</td><td>Active</td><td>Active via enrolled device agent</td></tr><tr><td>Device drop zone</td><td>Active</td><td>Active via enrolled device agent</td></tr><tr><td>Local file watcher</td><td>Active</td><td><code>C:/QiLabs/QiData/inbox/</code></td></tr><tr><td>Manual file upload</td><td>Active</td><td>App API → pipeline</td></tr><tr><td>Synced cloud storage</td><td>Planned</td><td>Non-canonical until registered via sync worker</td></tr><tr><td>Email intake</td><td>Future</td><td>Connector service</td></tr><tr><td>Webhook intake</td><td>Future</td><td>Integration API</td></tr><tr><td>Calendar sync</td><td>Future</td><td><code>qichronicle</code> connector</td></tr></tbody></table><p><em>Note: A device-assigned folder or drop zone is merely an <strong>ingress mechanism</strong>, not a canonical source itself. The integration law explicitly remains intact.</em></p><h2 id="integration-contract" tabindex="-1">Integration Contract <a class="header-anchor" href="#integration-contract" aria-label="Permalink to &quot;Integration Contract&quot;">​</a></h2><p>Every integration must define:</p><ul><li><strong>Trigger</strong>: what initiates the intake</li><li><strong>Format</strong>: what data arrives and in what shape</li><li><strong>Entry point</strong>: which API or queue receives the data</li><li><strong>Output</strong>: what canonical record is created</li><li><strong>Failure handling</strong>: what happens if the integration drops data</li></ul><h2 id="auth-for-integrations" tabindex="-1">Auth for Integrations <a class="header-anchor" href="#auth-for-integrations" aria-label="Permalink to &quot;Auth for Integrations&quot;">​</a></h2><p>External integrations must authenticate using:</p><ul><li><strong>Service role key</strong> for server-to-server (never expose to client)</li><li><strong>Scoped API key</strong> for third-party connectors</li><li><strong>JWT</strong> for user-context integrations</li></ul><p>Integrations may never bypass tenant isolation — every record created via integration must carry a <code>tenant_id</code>.</p><h2 id="email-pipeline-flow-contract" tabindex="-1">Email Pipeline Flow Contract <a class="header-anchor" href="#email-pipeline-flow-contract" aria-label="Permalink to &quot;Email Pipeline Flow Contract&quot;">​</a></h2><p>Email intake is considered a complex integration that must strictly obey the canonical registration pipeline:</p><ul><li><strong>Source</strong>: Gmail / Outlook / IMAP / webhook providers</li><li><strong>Entry</strong>: Integration API or background connector worker</li><li><strong>Flow</strong>: <ol><li><code>Connector Pull or Webhook</code></li><li><code>→ qisys Job / Event</code></li><li><code>→ qiarchive Registration</code></li><li><code>→ Extraction &amp; Attachments</code></li><li><code>→ Chunking &amp; Embedding</code></li><li><code>→ Routing/Review/Action</code></li></ol></li><li><strong>Worker Rule</strong>: All asynchronous worker inputs and outputs must pass and reference canonical IDs.</li><li><strong>Failure Rule</strong>: Failures must be visible, stateful, and cleanly retryable via <code>qisys</code>.</li><li><strong>Provenance Rule</strong>: The integration must NEVER bypass explicit <code>qiarchive</code> registration.</li><li><strong>Isolation Rule</strong>: Every derived email record must preserve <code>tenant_id</code> and obey Row-Level Security.</li></ul><h2 id="specific-service-integrations" tabindex="-1">Specific Service Integrations <a class="header-anchor" href="#specific-service-integrations" aria-label="Permalink to &quot;Specific Service Integrations&quot;">​</a></h2><ul><li><strong>Wiki.js</strong>: Runs locally at <code>127.0.0.1:3002</code>. Verified internal/admin route via Tailscale Serve: <code>https://qiserver-1.cerberus-sirius.ts.net:9448</code>. Public Cloudflare route <code>https://wiki.qially.com</code> currently returns Bad Gateway and should be labeled degraded until the tunnel route is repaired. Future Wiki.js sync may happen by script or workflow, but do not build it now.</li><li><strong>Paperless-ngx</strong>: Runs locally at <code>127.0.0.1:8010</code>. Paperless metadata must be configured before bulk import. Paperless should be tested with 10 documents max before large ingestion.</li></ul>',20)])])}const h=e(r,[["render",o]]);export{p as __pageData,h as default};
